import subprocess
import sys
import shutil
import os

def install_dependencies():
    print("Installing project dependencies...")
    try:
        subprocess.run([sys.executable, "-m", "pip", "install", "-r", "requirements.txt"], check=True)
        print("Dependencies installed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Error installing dependencies: {e}")
        sys.exit(1)

def run_tests():
    print("Running application tests...")
    try:
        # Assuming tests can be run with 'pytest' or 'python -m unittest discover'
        # Adjust this command based on your project's testing framework
        subprocess.run([sys.executable, "-m", "pytest"], check=True)
        print("Tests passed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Tests failed: {e}")
        sys.exit(1)
    except FileNotFoundError:
        print("pytest not found. Please ensure it's installed or adjust the test command.")
        sys.exit(1)

def package_for_deployment():
    print("Packaging application for deployment...")
    package_name = "deployment_package"
    
    # Clean up previous package if it exists
    if os.path.exists(package_name):
        shutil.rmtree(package_name)

    os.makedirs(package_name)

    # Define files/directories to include in the package
    # Customize this list based on your project structure
    files_to_include = [
        "app/",  # Your main application code directory
        "requirements.txt",
        "start.sh", # Example startup script
        "config.ini", # Example configuration file
        # Add any other necessary files or directories
    ]

    try:
        for item in files_to_include:
            if os.path.isfile(item):
                shutil.copy(item, package_name)
            elif os.path.isdir(item):
                shutil.copytree(item, os.path.join(package_name, os.path.basename(item)))
            else:
                print(f"Warning: Item '{item}' not found, skipping.")
        
        # Example: Create a zip archive of the package
        archive_name = shutil.make_archive(package_name, 'zip', root_dir='.', base_dir=package_name)
        print(f"Application packaged successfully: {archive_name}")
        
        # Optional: Clean up the temporary directory
        shutil.rmtree(package_name)
        
    except Exception as e:
        print(f"Error packaging application: {e}")
        sys.exit(1)

if __name__ == "__main__":
    install_dependencies()
    run_tests()
    package_for_deployment()
    print("Deployment preparation complete.")